// Filtrar solo las reseñas con estado_procesado = 'pendiente'
// y construir batches de 20 para OpenAI
const items = $input.all();

const pendientes = items.filter(i =>
  String(i.json.estado_procesado || '').trim().toLowerCase() === 'pendiente' &&
  String(i.json.texto_original || '').trim().length > 5
);

console.log(`[VOC Análisis] Total filas: ${items.length} | Pendientes: ${pendientes.length}`);

if (pendientes.length === 0) {
  return [{ json: { _voc_empty: true, mensaje: 'Sin reseñas pendientes de análisis' } }];
}

// Construir batches de 20 (óptimo para gpt-4o-mini: costo vs contexto)
const BATCH_SIZE = 20;
const batches = [];

for (let i = 0; i < pendientes.length; i += BATCH_SIZE) {
  const batch = pendientes.slice(i, i + BATCH_SIZE);
  batches.push({
    json: {
      batch_index: Math.floor(i / BATCH_SIZE),
      batch_total: Math.ceil(pendientes.length / BATCH_SIZE),
      resenas: batch.map(item => ({
        id:             item.json.id,
        texto:          item.json.texto_original,
        fuente:         item.json.fuente,
        calificacion:   item.json.calificacion_estrella,
        row_index:      item.json._rowIndex || null
      }))
    }
  });
}

console.log(`[VOC Análisis] Batches creados: ${batches.length} (${BATCH_SIZE} reseñas c/u)`);
return batches;

