// Parsear respuesta de OpenAI y preparar updates para el Master Sheet
const response = $input.first().json;

// Extraer el contenido del mensaje
const content = response.choices?.[0]?.message?.content;
if (!content) {
  throw new Error('[VOC OpenAI] Respuesta vacía de OpenAI: ' + JSON.stringify(response));
}

// Parsear JSON (response_format: json_object garantiza JSON válido)
let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error('[VOC OpenAI] Error parseando JSON: ' + content.substring(0, 200));
}

const resultados = parsed.resultados || [];
console.log(`[VOC OpenAI] Resultados parseados: ${resultados.length}`);

// Construir un item por reseña analizada para actualizar el Master Sheet
const updates = resultados.map(r => ({
  json: {
    id:               r.id,
    idioma:           r.idioma           || 'es',
    sentimiento:      r.sentimiento      || 'neutral',
    categoria:        r.categoria        || 'otro',
    score_urgencia:   r.score_urgencia   || 1,
    entidades_clave:  r.entidades_clave  || '',
    resumen_ia:       r.resumen_ia       || '',
    accion_sugerida:  r.accion_sugerida  || '',
    estado_procesado: 'procesado',
    // Metadata para el log
    _tokens_usados:   response.usage?.total_tokens || 0
  }
}));

console.log(`[VOC OpenAI] Updates listos: ${updates.length} | Tokens usados: ${response.usage?.total_tokens || 0}`);
return updates;

// Encontrar el row number de cada reseña en el Master Sheet
// para hacer el update en la fila correcta
const analizado = $input.first().json;
const masterItems = $('Leer pendientes del Master').all();

// Buscar la fila que tiene el mismo id
const matchingRow = masterItems.find(row => row.json.id === analizado.id);

if (!matchingRow) {
  console.log(`[VOC Update] ID no encontrado en Master: ${analizado.id}`);
  return [{ json: { ...analizado, _skip: true } }];
}

// n8n Google Sheets usa _rowIndex (1-based, fila 1 = headers)
// El row number real = índice en el array + 2 (1 por header + 1 por 0-index)
const rowNumber = masterItems.indexOf(matchingRow) + 2;

console.log(`[VOC Update] ID: ${analizado.id} → fila ${rowNumber}`);

return [{
  json: {
    ...analizado,
    _row_number: rowNumber
  }
}];

// Enrutamiento de alertas por categoría para LOGYCA/LAB
// Cada categoría va al responsable correcto
const item = $input.first().json;

const ROUTING = {
  'experiencia_espacio':  { equipo: 'Coordinación del LAB',    canal: $vars.SLACK_WEBHOOK_URL },
  'calidad_contenido':    { equipo: 'Equipo de Innovación',    canal: $vars.SLACK_WEBHOOK_URL },
  'tecnologia_demos':     { equipo: 'Equipo Técnico del LAB',  canal: $vars.SLACK_WEBHOOK_URL },
  'logistica_visita':     { equipo: 'Coordinación del LAB',    canal: $vars.SLACK_WEBHOOK_URL },
  'valor_percibido':      { equipo: 'Equipo de Membresía',     canal: $vars.SLACK_WEBHOOK_URL },
  'networking':           { equipo: 'Equipo de Comunidad',     canal: $vars.SLACK_WEBHOOK_URL },
  'atencion_equipo':      { equipo: 'Coordinación RRHH',       canal: $vars.SLACK_WEBHOOK_URL },
  'otro':                 { equipo: 'Coordinación del LAB',    canal: $vars.SLACK_WEBHOOK_URL }
};

const ruta = ROUTING[item.categoria] || ROUTING['otro'];

// Score visual
const scoreEmoji = item.score_urgencia >= 5 ? '🚨' : '⚠️';
const sentimientoEmoji = { positivo: '✅', neutral: '➖', negativo: '❌' }[item.sentimiento] || '➖';

const mensaje = {
  text: `${scoreEmoji} *Alerta VOC — LOGYCA/LAB* ${scoreEmoji}`,
  attachments: [
    {
      color: item.score_urgencia >= 5 ? '#E24B4A' : '#EF9F27',
      fields: [
        { title: 'Equipo responsable', value: ruta.equipo,            short: true  },
        { title: 'Categoría',          value: item.categoria,         short: true  },
        { title: 'Urgencia',           value: `${item.score_urgencia}/5`, short: true },
        { title: 'Sentimiento',        value: `${sentimientoEmoji} ${item.sentimiento}`, short: true },
        { title: 'Resumen IA',         value: item.resumen_ia,        short: false },
        { title: 'Acción sugerida',    value: item.accion_sugerida,   short: false },
        { title: 'Entidades mencionadas', value: item.entidades_clave || 'Ninguna', short: false }
      ],
      footer: 'VOC Pipeline · LOGYCA/LAB · Análisis automático',
      ts: Math.floor(Date.now() / 1000)
    }
  ]
};

return [{ json: { mensaje, webhook_url: ruta.canal, categoria: item.categoria, equipo: ruta.equipo } }];
